    10→  type AppliedFilters,
    11→} from '../../services/models';
    12→
    13→export interface PointsExtractActions {
    14→  setExtractStatus: (status: PointsExtractStatus) => void;
    15→  setExtractData: (extractData: PointsExtractData, processedExtractData?: ProcessedExtractData) => void;
    16→  appendExtractData: (extractData: PointsExtractData, processedExtractData?: ProcessedExtractData) => void;
    17→  setLoadingMore: (isLoading: boolean) => void;
    18→  setBalanceStatus: (status: PointsBalanceStatus) => void;
    19→  setBalance: (points?: number) => void;
    20→  setTransactionsFilters: (filters: AppliedFilters) => void;
    21→  clearTransactionsFilters: () => void;
    22→  reset: () => void;
    23→}
    24→
    25→export interface PointsExtractSlice {
    26→  pointsExtract: PointsExtractState;
    27→  pointsBalance: PointsBalanceState;
    28→  pointsExtractFilters: PointsExtractFiltersState;
    29→  pointsExtractActions: PointsExtractActions;
    30→}
    31→
    32→const INITIAL_POINTS_EXTRACT_STATE: PointsExtractState = {
    33→  extractData: undefined,
    34→  processedExtractData: undefined,
    35→  status: PointsExtractStatus.IDLE,
    36→  isLoadingMore: false,
    37→  error: undefined,
    38→};
    39→
    40→const INITIAL_POINTS_BALANCE_STATE: PointsBalanceState = {
    41→  points: undefined,
    42→  status: PointsBalanceStatus.IDLE,
    43→  error: undefined,
    44→};
    45→
    46→const INITIAL_POINTS_EXTRACT_FILTERS_STATE: PointsExtractFiltersState = {
    47→  appliedTransactionsFilters: undefined,
    48→};
    49→
    50→export const createPointsExtractSlice: StateCreator<
    51→  PointsExtractSlice,
    52→  [],
    53→  [],
    54→  PointsExtractSlice
    55→> = (set) => ({
    56→  pointsExtract: INITIAL_POINTS_EXTRACT_STATE,
    57→  pointsBalance: INITIAL_POINTS_BALANCE_STATE,
    58→  pointsExtractFilters: INITIAL_POINTS_EXTRACT_FILTERS_STATE,
    59→  pointsExtractActions: {
    60→    setExtractStatus: (status) =>
    61→      set((state) => ({
    62→        pointsExtract: { ...state.pointsExtract, status },
    63→      })),
    64→    setExtractData: (extractData, processedExtractData) =>
    65→      set((state) => ({
    66→        pointsExtract: {
    67→          ...state.pointsExtract,
    68→          extractData,
    69→          processedExtractData,
    70→          status: PointsExtractStatus.SUCCESS,
    71→          isLoadingMore: false,
    72→          error: undefined,
    73→        },
    74→      })),
    75→    appendExtractData: (extractData, processedExtractData) =>
    76→      set((state) => {
    77→        const existingTransactions = state.pointsExtract.extractData?.transactions ?? [];
    78→        const newTransactions = extractData.transactions;
    79→        const mergedTransactions = [...existingTransactions, ...newTransactions];
    80→
    81→        const existingProcessed = state.pointsExtract.processedExtractData;
    82→        const newProcessed = processedExtractData;
    83→
    84→        let mergedProcessed: ProcessedExtractData | undefined;
    85→        if (existingProcessed && newProcessed) {
    86→          const existingMapped = existingProcessed.mappedTransactions ?? [];
    87→          const newMapped = newProcessed.mappedTransactions ?? [];
    88→          mergedProcessed = {
    89→            groupedTransactions: newProcessed.groupedTransactions,
    90→            mappedTransactions: [...existingMapped, ...newMapped],
    91→          };
    92→        } else {
    93→          mergedProcessed = newProcessed ?? existingProcessed;
    94→        }
    95→
    96→        return {
    97→          pointsExtract: {
    98→            ...state.pointsExtract,
    99→            extractData: {
   100→              transactions: mergedTransactions,
   101→              pagination: extractData.pagination,
   102→            },
   103→            processedExtractData: mergedProcessed,
   104→            isLoadingMore: false,
   105→          },
   106→        };
   107→      }),
   108→    setLoadingMore: (isLoading) =>
   109→      set((state) => ({
   110→        pointsExtract: { ...state.pointsExtract, isLoadingMore: isLoading },
   111→      })),
